const results = [];

for (const item of $input.all()) {
  const d = item.json;

  // Strategic interpretation based on change_type
  let strategic_interpretation;
  switch (d.change_type) {
    case 'plan_added':
      strategic_interpretation = 'New tier introduction signals market expansion strategy';
      break;
    case 'plan_removed':
      strategic_interpretation = 'Tier consolidation suggests simplification push or segment abandonment';
      break;
    case 'model_change':
      strategic_interpretation = 'Pricing model shift indicates fundamental monetization strategy change';
      break;
    case 'gating_change':
      strategic_interpretation = 'Feature gating adjustment reveals conversion optimization or competitive response';
      break;
    case 'limit_change':
      strategic_interpretation = 'Usage limit changes signal capacity adjustment or margin optimization';
      break;
    case 'trial_change':
      strategic_interpretation = 'Trial structure change targets acquisition funnel optimization';
      break;
    case 'free_tier_change':
      strategic_interpretation = 'Free tier modification impacts bottom-of-funnel strategy';
      break;
    case 'enterprise_change':
      strategic_interpretation = 'Enterprise tier change targets upmarket positioning';
      break;
    default:
      strategic_interpretation = d.interpretation || 'Packaging change detected requiring strategic review';
      break;
  }

  // Response recommendations
  const recommendations = [
    {
      action: 'Monitor',
      description: 'Track follow-on changes from this competitor over next 30 days',
      priority: 'medium'
    }
  ];

  if (d.significance === 'high' || d.significance === 'critical') {
    recommendations.push({
      action: 'Review positioning',
      description: 'Assess whether your positioning needs adjustment in response',
      priority: 'high'
    });
  }

  if (d.change_type === 'gating_change' || d.change_type === 'model_change') {
    recommendations.push({
      action: 'Update battlecard',
      description: 'Refresh competitive battlecard with new packaging details',
      priority: 'high'
    });
  }

  if (d.change_type === 'plan_added' || d.change_type === 'free_tier_change') {
    recommendations.push({
      action: 'Evaluate response',
      description: 'Consider whether a packaging counter-move is warranted',
      priority: 'medium'
    });
  }

  // Severity
  const severity = (d.significance === 'high' || d.significance === 'critical') ? 'major' : 'minor';

  // Signal type mapping
  let signal_type;
  switch (d.change_type) {
    case 'plan_added':
    case 'plan_removed':
      signal_type = 'packaging_tier_change';
      break;
    case 'model_change':
      signal_type = 'packaging_metric_shift';
      break;
    case 'gating_change':
      signal_type = 'packaging_gate_change';
      break;
    default:
      signal_type = 'packaging_tier_change';
      break;
  }

  results.push({
    json: {
      user_id: d.user_id,
      company_name: d.company_name,
      company_id: d.company_id,
      change_id: d.change_id,
      change_type: d.change_type,
      strategic_interpretation,
      response_recommendations: JSON.stringify(recommendations),
      severity,
      change_details: typeof d.change_details === 'string' ? d.change_details : JSON.stringify(d.change_details),
      signal_type
    }
  });
}

return results;
